function DefaultCurrency385() {}
DefaultCurrency385.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency385.tabIndex = -1;
DefaultCurrency385.maxLength = 1;
DefaultCurrency385.isReadOnly = function(){return true;}
DefaultCurrency385.isTemporary = function(){return true;}
DefaultCurrency385.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency385.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }

Context.validate:
var val = Services.getValue(OutstandingAmt.dataBinding);
var err = WPU.validateCurrency(val);
if( null == err )
{	Services.setValue(OutstandingAmt.dataBinding, WPU.formatToTwoDP(val));
}
return err;
